CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE EXTENSION IF NOT EXISTS pgvector;
CREATE TABLE IF NOT EXISTS users (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), email VARCHAR(255) UNIQUE NOT NULL, role VARCHAR(50) NOT NULL DEFAULT 'operator', updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS conversations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), owner_id UUID REFERENCES users(id) ON DELETE CASCADE NOT NULL, title VARCHAR(255) DEFAULT 'New SHIMS Chat' NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL, updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS messages (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), conversation_id UUID REFERENCES conversations(id) ON DELETE CASCADE NOT NULL, sender_id UUID REFERENCES users(id) ON DELETE SET NULL, text_content TEXT NOT NULL, metadata JSONB DEFAULT '{}'::jsonb NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS edge_embeddings (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), message_id UUID REFERENCES messages(id) ON DELETE CASCADE NOT NULL, vector_payload vector(768) NOT NULL, raw_chunk_text TEXT NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS gst_einvoices (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), invoice_number VARCHAR(100) UNIQUE NOT NULL, irn_hash CHAR(64) UNIQUE, signed_qr_code TEXT, payload JSONB NOT NULL, ack_number VARCHAR(100), ack_date TIMESTAMP WITH TIME ZONE, status VARCHAR(50) DEFAULT 'draft' NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL);
CREATE TABLE IF NOT EXISTS gst_ewaybills (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), einvoice_id UUID REFERENCES gst_einvoices(id) ON DELETE SET NULL, ewaybill_number VARCHAR(100) UNIQUE, vehicle_number VARCHAR(50) NOT NULL, distance_km INT NOT NULL, transporter_id VARCHAR(50), transit_status VARCHAR(50) DEFAULT 'scheduled' NOT NULL, payload JSONB DEFAULT '{}'::jsonb NOT NULL, created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP NOT NULL);
CREATE INDEX IF NOT EXISTS idx_conversations_owner ON conversations(owner_id);
CREATE INDEX IF NOT EXISTS idx_messages_conversation ON messages(conversation_id);
CREATE INDEX IF NOT EXISTS idx_embeddings_vector ON edge_embeddings USING hnsw (vector_payload vector_cosine_ops);
